local cjson = require("cjson")

-- Simple XML parser that handles entity references
-- Compatible with OpenResty environment

local XmlParser = {}
XmlParser.__index = XmlParser

-- Entity reference mappings (standard + common custom)
local standard_entities = {
    ["&amp;"]  = "&",
    ["&lt;"]   = "<",
    ["&gt;"]   = ">",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

local function decode_entities(s)
    if not s then return s end
    -- Handle standard named entities
    s = s:gsub("(&%w+;)", function(entity)
        return standard_entities[entity] or entity
    end)
    -- Handle numeric character references (decimal)
    s = s:gsub("&#(%d+);", function(num)
        return string.char(tonumber(num))
    end)
    -- Handle numeric character references (hex)
    s = s:gsub("&#x(%x+);", function(num)
        return string.char(tonumber(num, 16))
    end)
    return s
end

local function trim(s)
    if not s then return s end
    return s:match("^%s*(.-)%s*$")
end

-- Parse XML attributes from a tag string
local function parse_attributes(attr_string)
    local attrs = {}
    if not attr_string then return attrs end
    for name, value in attr_string:gmatch('([%w_:%-]+)%s*=%s*"(.-)"') do
        attrs[name] = decode_entities(value)
    end
    for name, value in attr_string:gmatch("([%w_:%-]+)%s*=%s*'(.-)'") do
        attrs[name] = decode_entities(value)
    end
    return attrs
end

-- Recursive XML parser
local function parse_xml_node(xml, pos)
    local nodes = {}
    local text_buffer = ""

    while pos <= #xml do
        -- Look for the next tag
        local tag_start = xml:find("<", pos)

        if not tag_start then
            -- Remaining text
            local remaining = trim(decode_entities(xml:sub(pos)))
            if remaining and remaining ~= "" then
                text_buffer = text_buffer .. remaining
            end
            break
        end

        -- Collect text before the tag
        if tag_start > pos then
            local text_segment = xml:sub(pos, tag_start - 1)
            text_segment = trim(decode_entities(text_segment))
            if text_segment and text_segment ~= "" then
                text_buffer = text_buffer .. text_segment
            end
        end

        -- Check for comments
        if xml:sub(tag_start, tag_start + 3) == "<!--" then
            local comment_end = xml:find("-->", tag_start + 4)
            if comment_end then
                pos = comment_end + 3
            else
                pos = #xml + 1
            end

        -- Check for CDATA
        elseif xml:sub(tag_start, tag_start + 8) == "<![CDATA[" then
            local cdata_end = xml:find("]]>", tag_start + 9)
            if cdata_end then
                local cdata_content = xml:sub(tag_start + 9, cdata_end - 1)
                text_buffer = text_buffer .. cdata_content
                pos = cdata_end + 3
            else
                pos = #xml + 1
            end

        -- Check for processing instructions (<?...?>)
        elseif xml:sub(tag_start, tag_start + 1) == "<?" then
            local pi_end = xml:find("?>", tag_start + 2)
            if pi_end then
                pos = pi_end + 2
            else
                pos = #xml + 1
            end

        -- Check for closing tag
        elseif xml:sub(tag_start, tag_start + 1) == "</" then
            local close_end = xml:find(">", tag_start + 2)
            if close_end then
                pos = close_end + 1
            else
                pos = #xml + 1
            end
            -- Return to parent
            break

        -- Opening tag
        else
            local tag_end = xml:find(">", tag_start + 1)
            if not tag_end then
                pos = #xml + 1
                break
            end

            local tag_content = xml:sub(tag_start + 1, tag_end - 1)
            local self_closing = false

            if tag_content:sub(-1) == "/" then
                self_closing = true
                tag_content = tag_content:sub(1, -2)
            end

            -- Extract tag name and attributes
            local tag_name, attr_string = tag_content:match("^([%w_:%-]+)%s*(.*)")
            if not tag_name then
                pos = tag_end + 1
            else
                local node = {
                    tag = tag_name,
                    attrs = parse_attributes(attr_string),
                    children = {},
                    text = nil,
                }

                -- Extract namespace prefix and local name
                local ns_prefix, local_name = tag_name:match("^([%w_%-]+):([%w_%-]+)$")
                if ns_prefix then
                    node.namespace_prefix = ns_prefix
                    node.local_name = local_name
                else
                    node.namespace_prefix = nil
                    node.local_name = tag_name
                end

                if self_closing then
                    pos = tag_end + 1
                else
                    -- Parse children recursively
                    local child_nodes
                    child_nodes, pos = parse_xml_node(xml, tag_end + 1)

                    if type(child_nodes) == "table" then
                        for _, child in ipairs(child_nodes) do
                            if type(child) == "table" and child.tag then
                                table.insert(node.children, child)
                            end
                        end
                    end

                    -- If child_nodes returned text content
                    if child_nodes and child_nodes._text then
                        node.text = child_nodes._text
                    elseif type(child_nodes) == "table" and #child_nodes == 0 and child_nodes._text_buffer then
                        node.text = child_nodes._text_buffer
                    end
                end

                -- Handle text content for leaf nodes
                if #node.children == 0 and not node.text then
                    -- Find text between open and close tag
                    local inner_start = tag_end + 1
                    local close_pattern = "</" .. tag_name:gsub("([%(%)%.%%%+%-%*%?%[%]%^%$])", "%%%1") .. "%s*>"
                    local close_start = xml:find(close_pattern, inner_start)
                    if close_start and not self_closing then
                        local inner_text = xml:sub(inner_start, close_start - 1)
                        inner_text = trim(decode_entities(inner_text))
                        if inner_text and inner_text ~= "" then
                            node.text = inner_text
                        end
                    end
                end

                table.insert(nodes, node)
                -- After a closing tag, position should be after >
                if not self_closing then
                    local close_pattern = "</" .. tag_name:gsub("([%(%)%.%%%+%-%*%?%[%]%^%$])", "%%%1") .. "%s*>"
                    local _, close_end_pos = xml:find(close_pattern, tag_end + 1)
                    if close_end_pos then
                        pos = close_end_pos + 1
                    end
                end
            end
        end
    end

    -- Attach accumulated text
    if text_buffer ~= "" then
        nodes._text_buffer = text_buffer
    end

    return nodes, pos
end

function XmlParser.parse(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "Empty XML input"
    end

    -- Remove BOM if present
    if xml_string:sub(1, 3) == "\239\187\191" then
        xml_string = xml_string:sub(4)
    end

    local ok, result = pcall(function()
        local nodes, _ = parse_xml_node(xml_string, 1)
        if nodes and #nodes > 0 then
            return nodes[1] -- Return root element
        end
        return nil
    end)

    if not ok then
        return nil, "XML parsing error: " .. tostring(result)
    end

    return result
end

-- Utility: Find a child node by tag name (supports namespace-aware lookup)
local function find_child(node, tag_name, use_local_name)
    if not node or not node.children then return nil end
    for _, child in ipairs(node.children) do
        if use_local_name then
            if child.local_name == tag_name then
                return child
            end
        else
            if child.tag == tag_name or child.local_name == tag_name then
                return child
            end
        end
    end
    return nil
end

-- Utility: Find all children by tag name
local function find_all_children(node, tag_name, use_local_name)
    local results = {}
    if not node or not node.children then return results end
    for _, child in ipairs(node.children) do
        if use_local_name then
            if child.local_name == tag_name then
                table.insert(results, child)
            end
        else
            if child.tag == tag_name or child.local_name == tag_name then
                table.insert(results, child)
            end
        end
    end
    return results
end

-- Utility: Deep find a node by tag name (recursive)
local function find_deep(node, tag_name, use_local_name)
    if not node then return nil end
    if use_local_name then
        if node.local_name == tag_name then return node end
    else
        if node.tag == tag_name or node.local_name == tag_name then return node end
    end
    if node.children then
        for _, child in ipairs(node.children) do
            local found = find_deep(child, tag_name, use_local_name)
            if found then return found end
        end
    end
    return nil
end

-- Utility: Get text content of a node, including nested text
local function get_text(node)
    if not node then return nil end
    if node.text then return node.text end
    if node.children and #node.children == 0 then
        return node.text
    end
    -- Concatenate text from child nodes
    local parts = {}
    if node.children then
        for _, child in ipairs(node.children) do
            local child_text = get_text(child)
            if child_text then
                table.insert(parts, child_text)
            end
        end
    end
    if #parts > 0 then
        return table.concat(parts, " ")
    end
    return nil
end

-- Utility: Convert XML node to a Lua table (simplified)
local function node_to_table(node)
    if not node then return nil end

    local result = {}

    -- Add attributes
    if node.attrs then
        for k, v in pairs(node.attrs) do
            result["@" .. k] = v
        end
    end

    -- Leaf node with text
    if (not node.children or #node.children == 0) and node.text then
        if next(result) then
            -- Has attributes, add text as special key
            result["#text"] = node.text
            return result
        else
            return node.text
        end
    end

    -- Process children
    if node.children then
        for _, child in ipairs(node.children) do
            local child_key = child.local_name or child.tag
            local child_value = node_to_table(child)

            if result[child_key] then
                -- Multiple children with same name -> array
                if type(result[child_key]) ~= "table" or result[child_key][1] == nil then
                    result[child_key] = { result[child_key] }
                end
                table.insert(result[child_key], child_value)
            else
                result[child_key] = child_value
            end
        end
    end

    return result
end

-- ============================================================
-- SOAP-specific extraction utilities
-- ============================================================

local SoapProcessor = {}
SoapProcessor.__index = SoapProcessor

function SoapProcessor.new(xml_root)
    local self = setmetatable({}, SoapProcessor)
    self.root = xml_root
    self.envelope = nil
    self.header = nil
    self.body = nil
    self.fault = nil
    self:_extract_soap_parts()
    return self
end

function SoapProcessor:_extract_soap_parts()
    if not self.root then return end

    -- The root should be the Envelope
    local local_name = self.root.local_name or self.root.tag
    if local_name == "Envelope" then
        self.envelope = self.root
    else
        -- Try to find Envelope as a descendant
        self.envelope = find_deep(self.root, "Envelope", true)
    end

    if not self.envelope then return end

    -- Find Header and Body
    self.header = find_child(self.envelope, "Header", true)
    self.body = find_child(self.envelope, "Body", true)

    -- Check for Fault inside Body
    if self.body then
        self.fault = find_child(self.body, "Fault", true)
    end
end

function SoapProcessor:get_soap_action()
    -- Try to get from Header WS-Addressing Action
    if self.header then
        local action_node = find_child(self.header, "Action", true)
        if action_node and action_node.text then
            return action_node.text
        end
    end
    return nil
end

function SoapProcessor:get_body_operation()
    -- The first child of Body is typically the operation element
    if self.body and self.body.children and #self.body.children > 0 then
        local op = self.body.children[1]
        return {
            tag = op.tag,
            local_name = op.local_name,
            namespace_prefix = op.namespace_prefix,
            attrs = op.attrs,
        }
    end
    return nil
end

function SoapProcessor:get_body_content_as_table()
    if self.body and self.body.children and #self.body.children > 0 then
        return node_to_table(self.body.children[1])
    end
    return nil
end

function SoapProcessor:has_fault()
    return self.fault ~= nil
end

function SoapProcessor:get_fault_info()
    if not self.fault then return nil end

    local fault_info = {}
    -- SOAP 1.1 fault elements
    local faultcode = find_child(self.fault, "faultcode", true)
        or find_child(self.fault, "Code", true)
    local faultstring = find_child(self.fault, "faultstring", true)
        or find_child(self.fault, "Reason", true)
    local detail = find_child(self.fault, "detail", true)
        or find_child(self.fault, "Detail", true)

    fault_info.code = get_text(faultcode)
    fault_info.message = get_text(faultstring)
    if detail then
        fault_info.detail = node_to_table(detail)
    end

    return fault_info
end

function SoapProcessor:get_header_element(element_name)
    if not self.header then return nil end
    local elem = find_child(self.header, element_name, true)
    if elem then
        return node_to_table(elem)
    end
    return nil
end

function SoapProcessor:get_security_header()
    return self:get_header_element("Security")
end

-- ============================================================
-- SOAP Fault response builder
-- ============================================================

local function build_soap_fault(fault_code, fault_string, detail_str, soap_ns)
    soap_ns = soap_ns or "http://schemas.xmlsoap.org/soap/envelope/"
    local detail_xml = ""
    if detail_str then
        detail_xml = "<detail>" .. detail_str .. "</detail>"
    end
    return string.format(
        '<?xml version="1.0" encoding="UTF-8"?>' ..
        '<soap:Envelope xmlns:soap="%s">' ..
        '<soap:Body>' ..
        '<soap:Fault>' ..
        '<faultcode>%s</faultcode>' ..
        '<faultstring>%s</faultstring>' ..
        '%s' ..
        '</soap:Fault>' ..
        '</soap:Body>' ..
        '</soap:Envelope>',
        soap_ns,
        fault_code,
        fault_string,
        detail_xml
    )
end

-- ============================================================
-- OpenResty request handler
-- ============================================================

local function handle_soap_request()
    -- Read the request body
    ngx.req.read_body()
    local body = ngx.req.get_body_data()

    if not body then
        -- Body might be in a temp file
        local body_file = ngx.req.get_body_file()
        if body_file then
            local f = io.open(body_file, "r")
            if f then
                body = f:read("*a")
                f:close()
            end
        end
    end

    if not body or body == "" then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Empty request body"))
        return ngx.exit(400)
    end

    -- Validate content type
    local content_type = ngx.req.get_headers()["Content-Type"] or ""
    if not content_type:find("text/xml") and not content_type:find("application/soap%+xml") then
        ngx.log(ngx.WARN, "SOAP Gateway: Unexpected Content-Type: ", content_type)
        -- Continue processing anyway for flexibility
    end

    -- Get SOAPAction header (SOAP 1.1)
    local soap_action_header = ngx.req.get_headers()["SOAPAction"]
    if soap_action_header then
        -- Remove quotes if present
        soap_action_header = soap_action_header:gsub('^"(.*)"$', "%1")
    end

    -- Parse the XML
    local xml_root, parse_err = XmlParser.parse(body)
    if not xml_root then
        ngx.log(ngx.ERR, "SOAP Gateway: XML parse error: ", parse_err)
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Malformed XML: " .. (parse_err or "unknown error")))
        return ngx.exit(400)
    end

    -- Process SOAP structure
    local soap = SoapProcessor.new(xml_root)

    if not soap.envelope then
        ngx.log(ngx.ERR, "SOAP Gateway: No SOAP Envelope found")
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Missing SOAP Envelope"))
        return ngx.exit(400)
    end

    if not soap.body then
        ngx.log(ngx.ERR, "SOAP Gateway: No SOAP Body found")
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "Missing SOAP Body"))
        return ngx.exit(400)
    end

    -- Check for SOAP Fault in request (unusual but possible)
    if soap:has_fault() then
        local fault_info = soap:get_fault_info()
        ngx.log(ngx.WARN, "SOAP Gateway: Received SOAP Fault: ",
            cjson.encode(fault_info))
    end

    -- Extract operation information
    local operation = soap:get_body_operation()
    if not operation then
        ngx.log(ngx.ERR, "SOAP Gateway: No operation found in SOAP Body")
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Client", "No operation element in SOAP Body"))
        return ngx.exit(400)
    end

    -- Determine the SOAP action
    local soap_action = soap_action_header or soap:get_soap_action() or operation.local_name
    ngx.log(ngx.INFO, "SOAP Gateway: Processing action=", soap_action,
        " operation=", operation.local_name)

    -- Extract body parameters as a Lua table
    local request_params = soap:get_body_content_as_table()
    ngx.log(ngx.DEBUG, "SOAP Gateway: Request params: ", cjson.encode(request_params))

    -- Extract security/auth information from headers if present
    local security_info = soap:get_security_header()
    if security_info then
        ngx.log(ngx.DEBUG, "SOAP Gateway: Security header present")
        -- Store security context for downstream processing
        ngx.ctx.soap_security = security_info
    end

    -- Extract any custom header elements (e.g., correlation ID, session token)
    local message_id = soap:get_header_element("MessageID")
    if message_id then
        ngx.ctx.soap_message_id = message_id
        ngx.log(ngx.DEBUG, "SOAP Gateway: MessageID=", tostring(message_id))
    end

    -- Store extracted SOAP context for downstream use
    ngx.ctx.soap_action = soap_action
    ngx.ctx.soap_operation = operation
    ngx.ctx.soap_params = request_params
    ngx.ctx.soap_raw_body = body

    -- ============================================================
    -- Route to backend based on operation/action
    -- This section implements the gateway routing logic
    -- ============================================================

    -- Define routing table (operation -> backend configuration)
    local route_map = {
        -- Example routes - customize for your services
        ["GetUser"]          = { upstream = "user-service",     path = "/api/users/get" },
        ["CreateOrder"]      = { upstream = "order-service",    path = "/api/orders/create" },
        ["ProcessPayment"]   = { upstream = "payment-service",  path = "/api/payments/process" },
        ["GetInventory"]     = { upstream = "inventory-service", path = "/api/inventory/query" },
    }

    local route = route_map[operation.local_name]

    if route then
        -- Forward to appropriate backend upstream
        -- Set variables for proxy_pass in nginx config
        ngx.var.upstream_name = route.upstream
        ngx.var.upstream_path = route.path

        -- Add extracted parameters as headers for REST backends
        ngx.req.set_header("X-SOAP-Action", soap_action)
        ngx.req.set_header("X-SOAP-Operation", operation.local_name)
        if operation.namespace_prefix then
            ngx.req.set_header("X-SOAP-Namespace-Prefix", operation.namespace_prefix)
        end

        -- Optionally convert SOAP to JSON for REST backends
        local json_body = cjson.encode({
            action = soap_action,
            operation = operation.local_name,
            parameters = request_params,
            metadata = {
                message_id = message_id,
                timestamp = ngx.now(),
            }
        })

        ngx.req.set_header("Content-Type", "application/json")
        ngx.req.set_body_data(json_body)

        ngx.log(ngx.INFO, "SOAP Gateway: Routing ", operation.local_name,
            " to upstream=", route.upstream, " path=", route.path)

        -- Let nginx handle the proxy_pass
        return
    else
        -- Unknown operation - return SOAP fault
        ngx.log(ngx.WARN, "SOAP Gateway: Unknown operation: ", operation.local_name)
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault(
            "soap:Server",
            "Unknown operation: " .. (operation.local_name or "nil"),
            "<operations>" .. table.concat((function()
                local ops = {}
                for k, _ in pairs(route_map) do
                    table.insert(ops, k)
                end
                return ops
            end)(), ", ") .. "</operations>"
        ))
        return ngx.exit(500)
    end
end

-- ============================================================
-- Module exports
-- ============================================================

local _M = {
    -- Core parser
    XmlParser = XmlParser,

    -- SOAP processor
    SoapProcessor = SoapProcessor,

    -- Utility functions
    find_child = find_child,
    find_all_children = find_all_children,
    find_deep = find_deep,
    get_text = get_text,
    node_to_table = node_to_table,
    decode_entities = decode_entities,

    -- SOAP helpers
    build_soap_fault = build_soap_fault,

    -- Main request handler
    handle_soap_request = handle_soap_request,
}

-- Execute if called directly from OpenResty content phase
if ngx and ngx.get_phase() == "content" then
    local ok, err = pcall(handle_soap_request)
    if not ok then
        ngx.log(ngx.ERR, "SOAP Gateway: Unhandled error: ", err)
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(build_soap_fault("soap:Server", "Internal gateway error"))
        ngx.exit(500)
    end
end

return _M